export const adminDashboardDesign = {
  colors: {
    sidebar: "bg-gray-900 text-white",
    navbar: "bg-white shadow-md",
    overlay: "bg-black/40",
    hover: "hover:bg-gray-800",
    toggleBtn: "text-gray-700 hover:text-indigo-600 transition",
  },

  layout: {
    wrapper: "flex min-h-screen bg-gray-100",
    sidebar:
      "fixed top-0 left-0 h-full w-64 p-6 space-y-6 z-50 transform transition-transform duration-300 md:translate-x-0",
    contentWrapper: "flex-1 flex flex-col md:ml-64 w-full",
    navbar:
      "h-16 flex items-center justify-between px-6 bg-white shadow-md",
    content: "p-6",
    navItem: "px-3 py-2 rounded-lg transition cursor-pointer",
  },
};
